cat > /workspace/YatCC/task/2/antlr/SYsUParser.g4 << 'G4EOF'
parser grammar SYsUParser;

options {
  tokenVocab=SYsULexer;
}

// Entry point
compilationUnit
    :   translationUnit? EOF
    ;

translationUnit
    :   externalDeclaration+
    ;

externalDeclaration
    :   functionDefinition
    |   declaration
    ;

// Function definition
functionDefinition
    :   declarationSpecifiers directDeclarator '(' parameterTypeList? ')' compoundStatement
    ;

// Declarations
declaration
    :   declarationSpecifiers initDeclaratorList? ';'
    ;

declarationSpecifiers
    :   declarationSpecifier+
    ;

declarationSpecifier
    :   typeSpecifier
    |   typeQualifier
    ;

typeSpecifier
    :   Int
    |   Void
    |   Const
    ;

typeQualifier
    :   Const
    ;

initDeclaratorList
    :   initDeclarator (Comma initDeclarator)*
    ;

initDeclarator
    :   declarator (Equal initializer)?
    ;

declarator
    :   directDeclarator
    ;

directDeclarator
    :   Identifier
    |   directDeclarator LeftBracket assignmentExpression? RightBracket
    |   directDeclarator LeftParen parameterTypeList? RightParen
    ;

parameterTypeList
    :   parameterList (Comma Ellipsis)?
    |   Void
    ;

parameterList
    :   parameterDeclaration (Comma parameterDeclaration)*
    ;

parameterDeclaration
    :   declarationSpecifiers declarator
    |   declarationSpecifiers abstractDeclarator?
    ;

abstractDeclarator
    :   directAbstractDeclarator
    ;

directAbstractDeclarator
    :   LeftBracket assignmentExpression? RightBracket
    |   directAbstractDeclarator LeftBracket assignmentExpression? RightBracket
    |   LeftParen RightParen
    |   LeftParen directAbstractDeclarator RightParen
    ;

initializer
    :   assignmentExpression
    |   LeftBrace initializerList Comma? RightBrace
    ;

initializerList
    :   designation? initializer (Comma designation? initializer)*
    ;

designation
    :   designatorList Equal
    ;

designatorList
    :   designator+
    ;

designator
    :   LeftBracket assignmentExpression RightBracket
    |   Dot Identifier
    ;

// Statements
statement
    :   compoundStatement
    |   expressionStatement
    |   selectionStatement
    |   iterationStatement
    |   jumpStatement
    ;

compoundStatement
    :   LeftBrace blockItemList? RightBrace
    ;

blockItemList
    :   blockItem+
    ;

blockItem
    :   statement
    |   declaration
    ;

expressionStatement
    :   expression? Semi
    ;

selectionStatement
    :   If LeftParen expression RightParen statement (Else statement)?
    ;

iterationStatement
    :   While LeftParen expression RightParen statement
    |   For LeftParen expression? Semi expression? Semi expression? RightParen statement
    ;

jumpStatement
    :   Return expression? Semi
    |   Break Semi
    |   Continue Semi
    ;

// Expressions (precedence from lowest to highest)
expression
    :   assignmentExpression (Comma assignmentExpression)*
    ;

assignmentExpression
    :   conditionalExpression
    |   unaryExpression assignmentOperator assignmentExpression
    ;

assignmentOperator
    :   Equal | PlusEqual | MinusEqual | StarEqual | SlashEqual | PercentEqual 
    |   AmpersandEqual | PipeEqual | CaretEqual | LeftShiftEqual | RightShiftEqual
    ;

conditionalExpression
    :   logicalOrExpression (Question expression Colon conditionalExpression)?
    ;

logicalOrExpression
    :   logicalAndExpression (Or logicalAndExpression)*
    ;

logicalAndExpression
    :   inclusiveOrExpression (And inclusiveOrExpression)*
    ;

inclusiveOrExpression
    :   exclusiveOrExpression (Pipe exclusiveOrExpression)*
    ;

exclusiveOrExpression
    :   andExpression (Caret andExpression)*
    ;

andExpression
    :   equalityExpression (Ampersand equalityExpression)*
    ;

equalityExpression
    :   relationalExpression (EqualEqual relationalExpression | NotEqual relationalExpression)*
    ;

relationalExpression
    :   shiftExpression (Less shiftExpression | Greater shiftExpression | LessEqual shiftExpression | GreaterEqual shiftExpression)*
    ;

shiftExpression
    :   additiveExpression (LeftShift additiveExpression | RightShift additiveExpression)*
    ;

additiveExpression
    :   multiplicativeExpression (Plus multiplicativeExpression | Minus multiplicativeExpression)*
    ;

multiplicativeExpression
    :   castExpression (Star castExpression | Slash castExpression | Percent castExpression)*
    ;

castExpression
    :   LeftParen typeName RightParen castExpression
    |   unaryExpression
    ;

typeName
    :   typeSpecifier abstractDeclarator?
    ;

unaryExpression
    :   postfixExpression
    |   unaryOperator unaryExpression
    ;

unaryOperator
    :   Plus | Minus | Exclaim | Tilde
    ;

postfixExpression
    :   primaryExpression
    |   postfixExpression LeftBracket expression RightBracket
    |   postfixExpression LeftParen argumentExpressionList? RightParen
    |   postfixExpression Dot Identifier
    |   postfixExpression Arrow Identifier
    |   postfixExpression PlusPlus
    |   postfixExpression MinusMinus
    ;

primaryExpression
    :   Identifier
    |   Constant
    |   LeftParen expression RightParen
    ;

argumentExpressionList
    :   assignmentExpression (Comma assignmentExpression)*
    ;
G4EOF
